select count(*) from postgres.comments as c, postgres.posthistory as ph, postgres.badges as b, postgres.votes as v, postgres.users as u where ph.userid = u.id and v.userid = u.id and c.userid = u.id and b.userid = u.id and b."date">=timestamp '2010-09-26 12:17:14' and v.bountyamount>=0 and v.creationdate>=timestamp '2010-07-20 00:00:00' and v.creationdate<=timestamp '2014-09-11 00:00:00' and u.downvotes>=0 and u.downvotes<=0 and u.upvotes>=0 and u.upvotes<=31 and u.creationdate<=timestamp '2014-08-06 20:38:52';
